import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.CHSDihme.js";const p=JSON.parse('{"title":"Design System Specification: The Technical Atelier","description":"","frontmatter":{},"headers":[],"relativePath":"ui-clone/stitch_claudecode_haha_frontend_design/antique_codex/DESIGN.md","filePath":"ui-clone/stitch_claudecode_haha_frontend_design/antique_codex/DESIGN.md","lastUpdated":1780319135000}'),r={name:"ui-clone/stitch_claudecode_haha_frontend_design/antique_codex/DESIGN.md"};function s(n,e,l,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="design-system-specification-the-technical-atelier" tabindex="-1">Design System Specification: The Technical Atelier <a class="header-anchor" href="#design-system-specification-the-technical-atelier" aria-label="Permalink to &quot;Design System Specification: The Technical Atelier&quot;">​</a></h1><h2 id="1-overview--creative-north-star" tabindex="-1">1. Overview &amp; Creative North Star <a class="header-anchor" href="#1-overview--creative-north-star" aria-label="Permalink to &quot;1. Overview &amp; Creative North Star&quot;">​</a></h2><h3 id="the-creative-north-star-the-digital-archivist" tabindex="-1">The Creative North Star: &quot;The Digital Archivist&quot; <a class="header-anchor" href="#the-creative-north-star-the-digital-archivist" aria-label="Permalink to &quot;The Creative North Star: &quot;The Digital Archivist&quot;&quot;">​</a></h3><p>This design system moves away from the sterile, cold &quot;high-tech&quot; aesthetics typical of developer tools. Instead, it draws inspiration from high-end editorial design and architectural drafting—spaces designed for focus, tactile quality, and longevity. We are building a &quot;Digital Archivist&quot; experience: a workspace that feels like an expensive linen-bound notebook or a well-lit studio.</p><p>By utilizing intentional asymmetry, generous white space, and a rejection of traditional &quot;boxed&quot; layouts, we create an environment for deep work. The interface doesn&#39;t scream for attention; it recedes, providing a calm, authoritative stage for the developer’s code.</p><hr><h2 id="2-colors--surface-philosophy" tabindex="-1">2. Colors &amp; Surface Philosophy <a class="header-anchor" href="#2-colors--surface-philosophy" aria-label="Permalink to &quot;2. Colors &amp; Surface Philosophy&quot;">​</a></h2><p>The palette is rooted in &quot;Warm Paper&quot; (<code>#FAF9F5</code>) and &quot;Dark Graphite&quot; (<code>#141413</code>). This high-contrast but warm-toned foundation reduces eye strain during long coding sessions.</p><h3 id="the-no-line-rule" tabindex="-1">The &quot;No-Line&quot; Rule <a class="header-anchor" href="#the-no-line-rule" aria-label="Permalink to &quot;The &quot;No-Line&quot; Rule&quot;">​</a></h3><p>Traditional 1px borders are prohibited for structural sectioning. To define separate functional areas (e.g., a sidebar from a code editor), use background color shifts.</p><ul><li><strong>Application:</strong> Place a <code>surface_container_low</code> sidebar directly against a <code>surface</code> main content area. The 4% tonal shift is sufficient for the human eye to perceive a boundary without creating visual &quot;noise.&quot;</li></ul><h3 id="surface-hierarchy--nesting" tabindex="-1">Surface Hierarchy &amp; Nesting <a class="header-anchor" href="#surface-hierarchy--nesting" aria-label="Permalink to &quot;Surface Hierarchy &amp; Nesting&quot;">​</a></h3><p>Treat the UI as a physical stack of paper and glass.</p><ul><li><strong>Base Layer:</strong> <code>surface</code> (#FAF9F5) - The desk.</li><li><strong>Secondary Panels:</strong> <code>surface_container_low</code> (#F4F4F0) - Inset utility areas.</li><li><strong>Floating Elements:</strong> <code>surface_container_lowest</code> (#FFFFFF) - Active cards or modals.</li><li><strong>Nesting:</strong> Always move one tier up or down when nesting. A card (<code>surface_container_lowest</code>) should never sit on a background of the same color; it should sit on <code>surface_container_low</code> to create a natural, &quot;lifted&quot; appearance.</li></ul><h3 id="glassmorphism--tonal-depth" tabindex="-1">Glassmorphism &amp; Tonal Depth <a class="header-anchor" href="#glassmorphism--tonal-depth" aria-label="Permalink to &quot;Glassmorphism &amp; Tonal Depth&quot;">​</a></h3><p>For floating utilities (like a command palette or hover-state popover), use <code>surface_container_lowest</code> at 85% opacity with a <code>20px</code> backdrop blur. This allows the underlying code and &quot;warm paper&quot; texture to bleed through, maintaining a sense of place.</p><hr><h2 id="3-typography-editorial-authority" tabindex="-1">3. Typography: Editorial Authority <a class="header-anchor" href="#3-typography-editorial-authority" aria-label="Permalink to &quot;3. Typography: Editorial Authority&quot;">​</a></h2><p>The typography system pairs the modernist clarity of <strong>Manrope</strong> for high-level structure with the functional precision of <strong>Inter</strong> for data-heavy tasks.</p><ul><li><strong>Display &amp; Headlines (Manrope):</strong> These are the &quot;Wayfinders.&quot; Use <code>display-md</code> for empty states and <code>headline-sm</code> for major module titles. The slightly wider tracking of Manrope provides an expensive, editorial feel.</li><li><strong>Body &amp; Labels (Inter):</strong> Inter is our workhorse. Use <code>body-md</code> for standard UI text. It is optimized for screen readability and feels native to high-end macOS applications.</li><li><strong>Code (Monospace):</strong> For terminal output and code blocks, use a high-quality monospace font (SF Mono or JetBrains Mono) at <code>0.875rem</code> to match <code>body-md</code> visual weight.</li></ul><hr><h2 id="4-elevation--depth" tabindex="-1">4. Elevation &amp; Depth <a class="header-anchor" href="#4-elevation--depth" aria-label="Permalink to &quot;4. Elevation &amp; Depth&quot;">​</a></h2><p>We reject the &quot;drop shadow&quot; defaults of the web. Depth is an atmospheric quality, not a structural crutch.</p><ul><li><strong>The Layering Principle:</strong> Avoid shadows for static components. Use the <code>surface-container</code> tiers to create hierarchy.</li><li><strong>Ambient Shadows:</strong> For active floating states (Modals), use a multi-layered shadow: <ul><li><code>box-shadow: 0 4px 20px rgba(27, 28, 26, 0.04), 0 12px 40px rgba(27, 28, 26, 0.08);</code></li><li>The color is derived from <code>on_surface</code>, ensuring the shadow feels like a natural obstruction of light on warm paper.</li></ul></li><li><strong>The Ghost Border:</strong> When accessibility requires a container boundary, use <code>outline_variant</code> at 20% opacity. It should be felt, not seen.</li></ul><hr><h2 id="5-components" tabindex="-1">5. Components <a class="header-anchor" href="#5-components" aria-label="Permalink to &quot;5. Components&quot;">​</a></h2><h3 id="buttons" tabindex="-1">Buttons <a class="header-anchor" href="#buttons" aria-label="Permalink to &quot;Buttons&quot;">​</a></h3><ul><li><strong>Primary:</strong> <code>primary</code> (#8F482F) background with <code>on_primary</code> (#FFFFFF) text.</li><li><strong>Secondary:</strong> <code>surface_container_high</code> background. No border.</li><li><strong>Signature Styling:</strong> Use <code>radius-DEFAULT</code> (8px). For Primary buttons, apply a subtle linear gradient from <code>primary</code> to <code>primary_container</code> (top to bottom) to give the button a &quot;pressed ink&quot; physical quality.</li></ul><h3 id="the-chat-composer-input" tabindex="-1">The Chat Composer (Input) <a class="header-anchor" href="#the-chat-composer-input" aria-label="Permalink to &quot;The Chat Composer (Input)&quot;">​</a></h3><ul><li><strong>Styling:</strong> Large <code>radius-xl</code> (16px) corners.</li><li><strong>Background:</strong> <code>surface_container_lowest</code> (#FFFFFF).</li><li><strong>Definition:</strong> Instead of a heavy border, use a <code>1px</code> &quot;Ghost Border&quot; of <code>outline_variant</code> at 15% opacity. When focused, increase the opacity of the ghost border to 40%—do not use a glow.</li></ul><h3 id="chips--status" tabindex="-1">Chips &amp; Status <a class="header-anchor" href="#chips--status" aria-label="Permalink to &quot;Chips &amp; Status&quot;">​</a></h3><ul><li><strong>Success:</strong> <code>tertiary_container</code> (#677B4E) with <code>on_tertiary_container</code> text.</li><li><strong>Running/Warning:</strong> <code>primary_fixed</code> (#FFDBD0) with <code>on_primary_fixed</code> text.</li><li><strong>Shape:</strong> Use <code>radius-full</code> for a soft, pill-shaped aesthetic that contrasts against the structured grid of code.</li></ul><h3 id="cards--lists" tabindex="-1">Cards &amp; Lists <a class="header-anchor" href="#cards--lists" aria-label="Permalink to &quot;Cards &amp; Lists&quot;">​</a></h3><ul><li><strong>The No-Divider Rule:</strong> Explicitly forbid horizontal lines between list items. Separate items using <code>8px</code> of vertical white space or a hover state that shifts the background to <code>surface_container_highest</code>.</li><li><strong>Nesting:</strong> Cards must use <code>radius-lg</code> (12px) and be placed on <code>surface_container_low</code> for maximum legibility.</li></ul><h3 id="terminal--code-blocks" tabindex="-1">Terminal &amp; Code Blocks <a class="header-anchor" href="#terminal--code-blocks" aria-label="Permalink to &quot;Terminal &amp; Code Blocks&quot;">​</a></h3><ul><li><strong>Container:</strong> <code>surface_dim</code> (#DBDAD6) to provide a &quot;recessed&quot; look.</li><li><strong>Text:</strong> <code>on_surface</code> for standard output, <code>secondary</code> (#2D628F) for links/permissions.</li></ul><hr><h2 id="6-dos-and-donts" tabindex="-1">6. Do&#39;s and Don&#39;ts <a class="header-anchor" href="#6-dos-and-donts" aria-label="Permalink to &quot;6. Do&#39;s and Don&#39;ts&quot;">​</a></h2><h3 id="do" tabindex="-1">Do <a class="header-anchor" href="#do" aria-label="Permalink to &quot;Do&quot;">​</a></h3><ul><li><strong>Embrace Asymmetry:</strong> Align primary actions to the right, but keep &quot;Brand Moments&quot; (like a logo or status indicator) intentionally offset to break the &quot;Bootstrap&quot; feel.</li><li><strong>Use &quot;Warmth&quot; as a Tool:</strong> Use the <code>primary</code> (Antique Brass) color sparingly. It should highlight intent, not decorate.</li><li><strong>Prioritize Breathing Room:</strong> If a layout feels &quot;busy,&quot; increase the spacing scale rather than adding borders.</li></ul><h3 id="dont" tabindex="-1">Don&#39;t <a class="header-anchor" href="#dont" aria-label="Permalink to &quot;Don&#39;t&quot;">​</a></h3><ul><li><strong>No 100% Black:</strong> Never use <code>#000000</code>. Use <code>on_background</code> (#1B1C1A) to maintain the &quot;ink on paper&quot; softness.</li><li><strong>No Sharp Corners:</strong> Avoid <code>0px</code> or <code>2px</code> radii. They feel clinical and &quot;un-designed&quot; in this context.</li><li><strong>No &quot;Gaming&quot; Effects:</strong> Avoid neon glows, heavy blurs, or high-saturation blues. If it looks like a dashboard for a spaceship, it&#39;s wrong. It should look like a dashboard for a master craftsman.</li></ul><h3 id="accessibility-note" tabindex="-1">Accessibility Note <a class="header-anchor" href="#accessibility-note" aria-label="Permalink to &quot;Accessibility Note&quot;">​</a></h3><p>While we use subtle tonal shifts, always ensure the <code>on_surface</code> text vs <code>surface_container</code> maintains a minimum 4.5:1 contrast ratio for body text. Use <code>outline</code> (#87736D) for iconography to ensure clarity against the warm background.</p>',44)])])}const g=o(r,[["render",s]]);export{p as __pageData,g as default};
